namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@page "/apply"
@rendermode InteractiveServer
@using sv_fe5c3bf64a7543eabcf20521d982e0df.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1 class="mb-4">Job Application</h1>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="NavigateToStep" />

    @if (!submitted)
    {
        <div class="step-content mt-4">
            @switch (currentStep)
            {
                case 1:
                    <PersonalInfoStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                      FullNameChanged="v => fullName = v"
                                      EmailChanged="v => email = v"
                                      PhoneChanged="v => phone = v"
                                      AddressChanged="v => address = v"
                                      Errors="stepErrors"
                                      OnNext="HandleNextFromStep1" />
                    break;
                case 2:
                    <WorkHistoryStep WorkEntries="workEntries"
                                     Errors="stepErrors"
                                     OnBack="GoBack"
                                     OnNext="HandleNextFromStep2" />
                    break;
                case 3:
                    <ReferencesStep References="references"
                                    Errors="stepErrors"
                                    OnBack="GoBack"
                                    OnNext="HandleNextFromStep3" />
                    break;
                case 4:
                    <CoverLetterStep @bind-CoverLetter="coverLetter"
                                     MaxLength="2000"
                                     Errors="stepErrors"
                                     OnBack="GoBack"
                                     OnNext="HandleNextFromStep4" />
                    break;
                case 5:
                    <ReviewStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                WorkEntries="workEntries" References="references" CoverLetter="@coverLetter"
                                IsSubmitting="isSubmitting" SubmitError="@submitError"
                                OnEdit="NavigateToStep"
                                OnBack="GoBack"
                                OnSubmit="HandleSubmit" />
                    break;
            }
        </div>
    }
    else
    {
        <div class="text-center mt-5">
            <div class="mb-3">
                <span class="confirmation-icon">✅</span>
            </div>
            <h2>Application Submitted!</h2>
            <p class="text-muted">Your application has been received successfully.</p>
            <p class="fs-5">Your application ID is: <strong class="text-primary">#@applicationId</strong></p>
        </div>
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private Dictionary<string, string> stepErrors = new();
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;
    private string? submitError;

    // Step 1
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2
    private List<WorkEntryModel> workEntries = new() { new() };

    // Step 3
    private List<ReferenceModel> references = new() { new(), new() };

    // Step 4
    private string coverLetter = "";

    private void NavigateToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
        {
            stepErrors.Clear();
            currentStep = step;
        }
    }

    private void GoBack()
    {
        stepErrors.Clear();
        currentStep--;
    }

    private async Task HandleNextFromStep1()
    {
        stepErrors.Clear();

        if (string.IsNullOrWhiteSpace(fullName))
            stepErrors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(email))
            stepErrors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(phone))
            stepErrors["Phone"] = "Phone number is required.";
        if (string.IsNullOrWhiteSpace(address))
            stepErrors["Address"] = "Address is required.";

        if (stepErrors.Count > 0) return;

        var emailValid = await ApplicationService.ValidateEmailAsync(email);
        if (!emailValid)
        {
            stepErrors["Email"] = "Please enter a valid email address.";
            return;
        }

        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleNextFromStep2()
    {
        stepErrors.Clear();

        for (int i = 0; i < workEntries.Count; i++)
        {
            var e = workEntries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                stepErrors[$"Company_{i}"] = "Company name is required.";
            if (string.IsNullOrWhiteSpace(e.Title))
                stepErrors[$"Title_{i}"] = "Job title is required.";
            if (e.StartDate == default)
                stepErrors[$"StartDate_{i}"] = "Start date is required.";
        }

        if (stepErrors.Count > 0) return;

        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleNextFromStep3()
    {
        stepErrors.Clear();

        for (int i = 0; i < references.Count; i++)
        {
            var r = references[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                stepErrors[$"RefName_{i}"] = "Name is required.";
            if (string.IsNullOrWhiteSpace(r.Relationship))
                stepErrors[$"RefRelationship_{i}"] = "Relationship is required.";
            if (string.IsNullOrWhiteSpace(r.Email))
                stepErrors[$"RefEmail_{i}"] = "Email is required.";
            if (string.IsNullOrWhiteSpace(r.Phone))
                stepErrors[$"RefPhone_{i}"] = "Phone is required.";
        }

        if (stepErrors.Count > 0) return;

        completedSteps.Add(3);
        currentStep = 4;
    }

    private void HandleNextFromStep4()
    {
        stepErrors.Clear();

        if (string.IsNullOrWhiteSpace(coverLetter))
            stepErrors["CoverLetter"] = "Cover letter is required.";

        if (stepErrors.Count > 0) return;

        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var app = new JobApplication(
                new PersonalInfo(fullName, email, phone, address),
                new WorkHistory(workEntries.Select(e =>
                    new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)
                ).ToList()),
                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(app);
            completedSteps.Add(5);
            submitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

.apply-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem 1rem;
}

.confirmation-icon {
    font-size: 3rem;
}

@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply

<nav class="step-indicator d-flex justify-content-between mb-4" aria-label="Application steps">
    @for (int i = 0; i < stepNames.Length; i++)
    {
        var step = i + 1;
        var isCurrent = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var isClickable = isCompleted;

        <button type="button"
                class="step-item flex-fill text-center border-0 bg-transparent p-2 @(isCurrent ? "step-current" : isCompleted ? "step-completed" : "step-future")"
                disabled="@(!isClickable)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(isCurrent ? "step" : null)">
            <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                @if (isCompleted && !isCurrent)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <small class="@(isCurrent ? "fw-bold" : isCompleted ? "text-success" : "text-muted")">@stepNames[i]</small>
        </button>
    }
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] stepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    transition: all 0.2s;
}

.step-item {
    cursor: default;
    transition: opacity 0.2s;
}

.step-completed {
    cursor: pointer;
}

.step-future {
    opacity: 0.5;
}

button.step-item:disabled {
    opacity: 1;
    cursor: default;
}

button.step-future:disabled {
    opacity: 0.5;
}

@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply

<h3>Personal Information</h3>

<div class="mb-3">
    <label class="form-label" for="fullName">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @ErrorClass("FullName")"
           value="@FullName" @oninput="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    <ValidationMessage FieldKey="FullName" Errors="Errors" />
</div>

<div class="mb-3">
    <label class="form-label" for="email">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @ErrorClass("Email")"
           value="@Email" @oninput="e => EmailChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    <ValidationMessage FieldKey="Email" Errors="Errors" />
</div>

<div class="mb-3">
    <label class="form-label" for="phone">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @ErrorClass("Phone")"
           value="@Phone" @oninput="e => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    <ValidationMessage FieldKey="Phone" Errors="Errors" />
</div>

<div class="mb-3">
    <label class="form-label" for="address">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @ErrorClass("Address")" rows="2"
              @oninput="e => AddressChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Address</textarea>
    <ValidationMessage FieldKey="Address" Errors="Errors" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";

    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public EventCallback<string> AddressChanged { get; set; }

    [Parameter] public Dictionary<string, string> Errors { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }

    private string ErrorClass(string key) => Errors.ContainsKey(key) ? "is-invalid" : "";
}

@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply
@using static Apply

<h3>Work History</h3>

@for (int idx = 0; idx < WorkEntries.Count; idx++)
{
    var i = idx;
    var entry = WorkEntries[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Position @(i + 1)</h5>
                @if (WorkEntries.Count > 1)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(i)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass($"Company_{i}")"
                           value="@entry.Company" @oninput="e => entry.Company = e.Value?.ToString() ?? """/>
                    <ValidationMessage FieldKey="@($"Company_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass($"Title_{i}")"
                           value="@entry.Title" @oninput="e => entry.Title = e.Value?.ToString() ?? ""/>
                    <ValidationMessage FieldKey="@($"Title_{i}")" Errors="Errors" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control @ErrorClass($"StartDate_{i}")"
                           value="@FormatDate(entry.StartDate)"
                           @onchange="e => entry.StartDate = ParseDate(e.Value?.ToString())" />
                    <ValidationMessage FieldKey="@($"StartDate_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control"
                           value="@FormatDate(entry.EndDate)"
                           disabled="@entry.IsCurrent"
                           @onchange="e => entry.EndDate = ParseNullableDate(e.Value?.ToString())" />
                </div>
                <div class="col-md-4 mb-3 d-flex align-items-end">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="@($"current_{i}")"
                               checked="@entry.IsCurrent"
                               @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                        <label class="form-check-label" for="@($"current_{i}")">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3"
                          @oninput="e => entry.Description = e.Value?.ToString() ?? """>@entry.Description</textarea>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public Dictionary<string, string> Errors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => WorkEntries.Add(new());
    private void RemoveEntry(int index) => WorkEntries.RemoveAt(index);

    private string ErrorClass(string key) => Errors.ContainsKey(key) ? "is-invalid" : "";

    private static string FormatDate(DateTime date) =>
        date == default ? "" : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? "";

    private static DateTime ParseDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : default;

    private static DateTime? ParseNullableDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : null;
}

@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply
@using static Apply

<h3>References</h3>

@for (int idx = 0; idx < References.Count; idx++)
{
    var i = idx;
    var r = References[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Reference @(i + 1)</h5>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(i)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass($"RefName_{i}")"
                           value="@r.Name" @oninput="e => r.Name = e.Value?.ToString() ?? """/>
                    <ValidationMessage FieldKey="@($"RefName_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass($"RefRelationship_{i}")"
                           value="@r.Relationship" @oninput="e => r.Relationship = e.Value?.ToString() ?? """/>
                    <ValidationMessage FieldKey="@($"RefRelationship_{i}")" Errors="Errors" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control @ErrorClass($"RefEmail_{i}")"
                           value="@r.Email" @oninput="e => r.Email = e.Value?.ToString() ?? """/>
                    <ValidationMessage FieldKey="@($"RefEmail_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control @ErrorClass($"RefPhone_{i}")"
                           value="@r.Phone" @oninput="e => r.Phone = e.Value?.ToString() ?? """/>
                    <ValidationMessage FieldKey="@($"RefPhone_{i}")" Errors="Errors" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
