    font-size: 0.9rem;
    transition: all 0.2s;
}

.step-item {
    cursor: default;
    transition: opacity 0.2s;
}

.step-completed {
    cursor: pointer;
}

.step-future {
    opacity: 0.5;
}

button.step-item:disabled {
    opacity: 1;
    cursor: default;
}

button.step-future:disabled {
    opacity: 0.5;
}

