                    <input type="text" class="form-control @ErrorClass($"Company_{i}")"
                           value="@entry.Company" @oninput="e => entry.Company = e.Value?.ToString() ?? """/>
                    <ValidationMessage FieldKey="@($"Company_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass($"Title_{i}")"
                           value="@entry.Title" @oninput="e => entry.Title = e.Value?.ToString() ?? ""/>
                    <ValidationMessage FieldKey="@($"Title_{i}")" Errors="Errors" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control @ErrorClass($"StartDate_{i}")"
                           value="@FormatDate(entry.StartDate)"
                           @onchange="e => entry.StartDate = ParseDate(e.Value?.ToString())" />
                    <ValidationMessage FieldKey="@($"StartDate_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control"
                           value="@FormatDate(entry.EndDate)"
                           disabled="@entry.IsCurrent"
                           @onchange="e => entry.EndDate = ParseNullableDate(e.Value?.ToString())" />
