                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3"
                          @oninput="e => entry.Description = e.Value?.ToString() ?? """>@entry.Description</textarea>
            </div>
        </div>
    </div>
}

