{"path": "/tmp/sv-fe5c3bf64a7543eabcf20521d982e0df/Components/Pages/Apply/Apply.razor", "file_text": "@page "/apply"
@rendermode InteractiveServer
@using sv_fe5c3bf64a7543eabcf20521d982e0df.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1 class="mb-4">Job Application</h1>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="NavigateToStep" />

    @if (!submitted)
    {
        <div class="step-content mt-4">
            @switch (currentStep)
            {
                case 1:
                    <PersonalInfoStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                      FullNameChanged="v => fullName = v"
                                      EmailChanged="v => email = v"
                                      PhoneChanged="v => phone = v"
                                      AddressChanged="v => address = v"
                                      Errors="stepErrors"
                                      OnNext="HandleNextFromStep1" />
                    break;
                case 2:
                    <WorkHistoryStep WorkEntries="workEntries"
                                     Errors="stepErrors"
                                     OnBack="GoBack"
                                     OnNext="HandleNextFromStep2" />
                    break;
                case 3:
                    <ReferencesStep References="references"
                                    Errors="stepErrors"
                                    OnBack="GoBack"
                                    OnNext="HandleNextFromStep3" />
                    break;
                case 4:
                    <CoverLetterStep @bind-CoverLetter="coverLetter"
                                     MaxLength="2000"
                                     Errors="stepErrors"
                                     OnBack="GoBack"
                                     OnNext="HandleNextFromStep4" />
                    break;
                case 5:
                    <ReviewStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                WorkEntries="workEntries" References="references" CoverLetter="@coverLetter"
                                IsSubmitting="isSubmitting" SubmitError="@submitError"
                                OnEdit="NavigateToStep"
                                OnBack="GoBack"
                                OnSubmit="HandleSubmit" />
                    break;
            }
        </div>
    }
    else
    {
        <div class="text-center mt-5">
            <div class="mb-3">
                <span class="confirmation-icon">✅</span>
            </div>
            <h2>Application Submitted!</h2>
            <p class="text-muted">Your application has been received successfully.</p>
            <p class="fs-5">Your application ID is: <strong class="text-primary">#@applicationId</strong></p>
        </div>
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private Dictionary<string, string> stepErrors = new();
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;
    private string? submitError;

    // Step 1
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2
    private List<WorkEntryModel> workEntries = new() { new() };

    // Step 3
    private List<ReferenceModel> references = new() { new(), new() };

    // Step 4
    private string coverLetter = "";

    private void NavigateToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
        {
            stepErrors.Clear();
            currentStep = step;
        }
    }

    private void GoBack()
    {
        stepErrors.Clear();
        currentStep--;
    }

    private async Task HandleNextFromStep1()
    {
        stepErrors.Clear();

        if (string.IsNullOrWhiteSpace(fullName))
            stepErrors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(email))
            stepErrors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(phone))
            stepErrors["Phone"] = "Phone number is required.";
        if (string.IsNullOrWhiteSpace(address))
            stepErrors["Address"] = "Address is required.";

        if (stepErrors.Count > 0) return;

        var emailValid = await ApplicationService.ValidateEmailAsync(email);
        if (!emailValid)
        {
            stepErrors["Email"] = "Please enter a valid email address.";
            return;
        }

        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleNextFromStep2()
    {
        stepErrors.Clear();

        for (int i = 0; i < workEntries.Count; i++)
        {
            var e = workEntries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                stepErrors[$"Company_{i}"] = "Company name is required.";
            if (string.IsNullOrWhiteSpace(e.Title))
                stepErrors[$"Title_{i}"] = "Job title is required.";
            if (e.StartDate == default)
                stepErrors[$"StartDate_{i}"] = "Start date is required.";
        }

        if (stepErrors.Count > 0) return;

        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleNextFromStep3()
    {
        stepErrors.Clear();

        for (int i = 0; i < references.Count; i++)
        {
            var r = references[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                stepErrors[$"RefName_{i}"] = "Name is required.";
            if (string.IsNullOrWhiteSpace(r.Relationship))
                stepErrors[$"RefRelationship_{i}"] = "Relationship is required.";
            if (string.IsNullOrWhiteSpace(r.Email))
                stepErrors[$"RefEmail_{i}"] = "Email is required.";
            if (string.IsNullOrWhiteSpace(r.Phone))
                stepErrors[$"RefPhone_{i}"] = "Phone is required.";
        }

        if (stepErrors.Count > 0) return;

        completedSteps.Add(3);
        currentStep = 4;
    }

    private void HandleNextFromStep4()
    {
        stepErrors.Clear();

        if (string.IsNullOrWhiteSpace(coverLetter))
            stepErrors["CoverLetter"] = "Cover letter is required.";

        if (stepErrors.Count > 0) return;

        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var app = new JobApplication(
                new PersonalInfo(fullName, email, phone, address),
                new WorkHistory(workEntries.Select(e =>
                    new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)
                ).ToList()),
                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(app);
            completedSteps.Add(5);
            submitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}
"}

