{"path": "/tmp/sv-fe5c3bf64a7543eabcf20521d982e0df/Components/Pages/Apply/CoverLetterStep.razor", "file_text": "@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply

<h3>Cover Letter</h3>

<div class="mb-3">
    <label class="form-label" for="coverLetter">Write your cover letter <span class="text-danger">*</span></label>
    <textarea id="coverLetter"
              class="form-control @(Errors.ContainsKey("CoverLetter") ? "is-invalid" : "")"
              rows="12"
              maxlength="@MaxLength"
              @oninput="HandleInput">@CoverLetter</textarea>
    <ValidationMessage FieldKey="CoverLetter" Errors="Errors" />
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public int MaxLength { get; set; } = 2000;
    [Parameter] public Dictionary<string, string> Errors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        if (value.Length > MaxLength)
            value = value[..MaxLength];
        await CoverLetterChanged.InvokeAsync(value);
    }
}
"}

{"path": "/tmp/sv-fe5c3bf64a7543eabcf20521d982e0df/Components/Pages/Apply/ReviewStep.razor", "file_text": "@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply
@using static Apply

<h3>Review &amp; Submit</h3>
<p class="text-muted">Please review your application before submitting.</p>

<!-- Personal Info -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<!-- Work History -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-no-border">
                <h6 class="mb-1">@entry.Title at @entry.Company</h6>
                <small class="text-muted">
                    @entry.StartDate.ToString("MMM yyyy") –
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </small>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mt-1 mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<!-- References -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> — @r.Relationship<br />
                <small class="text-muted">@r.Email · @r.Phone</small>
            </div>
        }
    </div>
</div>

<!-- Cover Letter -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
            <span>Submitting...</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public string? SubmitError { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
}
"}

