@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply

<nav class="step-indicator d-flex justify-content-between mb-4" aria-label="Application steps">
    @for (int i = 0; i < stepNames.Length; i++)
    {
        var step = i + 1;
        var isCurrent = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var isClickable = isCompleted;

        <button type="button"
                class="step-item flex-fill text-center border-0 bg-transparent p-2 @(isCurrent ? "step-current" : isCompleted ? "step-completed" : "step-future")"
                disabled="@(!isClickable)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(isCurrent ? "step" : null)">
            <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                @if (isCompleted && !isCurrent)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <small class="@(isCurrent ? "fw-bold" : isCompleted ? "text-success" : "text-muted")">@stepNames[i]</small>
        </button>
    }
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] stepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };
}

