@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply

<h3>Personal Information</h3>

<div class="mb-3">
    <label class="form-label" for="fullName">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @ErrorClass("FullName")"
           value="@FullName" @oninput="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    <ValidationMessage FieldKey="FullName" Errors="Errors" />
</div>

<div class="mb-3">
    <label class="form-label" for="email">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @ErrorClass("Email")"
           value="@Email" @oninput="e => EmailChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    <ValidationMessage FieldKey="Email" Errors="Errors" />
</div>

<div class="mb-3">
    <label class="form-label" for="phone">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @ErrorClass("Phone")"
           value="@Phone" @oninput="e => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    <ValidationMessage FieldKey="Phone" Errors="Errors" />
</div>

<div class="mb-3">
    <label class="form-label" for="address">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @ErrorClass("Address")" rows="2"
              @oninput="e => AddressChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Address</textarea>
    <ValidationMessage FieldKey="Address" Errors="Errors" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";

    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public EventCallback<string> AddressChanged { get; set; }

    [Parameter] public Dictionary<string, string> Errors { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }

    private string ErrorClass(string key) => Errors.ContainsKey(key) ? "is-invalid" : "";
}

@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply
@using static Apply

<h3>Work History</h3>

@for (int idx = 0; idx < WorkEntries.Count; idx++)
{
    var i = idx;
    var entry = WorkEntries[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Position @(i + 1)</h5>
                @if (WorkEntries.Count > 1)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(i)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass($"Company_{i}")"
                           value="@entry.Company" @oninput="e => entry.Company = e.Value?.ToString() ?? """/>
                    <ValidationMessage FieldKey="@($"Company_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass($"Title_{i}")"
                           value="@entry.Title" @oninput="e => entry.Title = e.Value?.ToString() ?? ""/>
                    <ValidationMessage FieldKey="@($"Title_{i}")" Errors="Errors" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control @ErrorClass($"StartDate_{i}")"
                           value="@FormatDate(entry.StartDate)"
                           @onchange="e => entry.StartDate = ParseDate(e.Value?.ToString())" />
                    <ValidationMessage FieldKey="@($"StartDate_{i}")" Errors="Errors" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control"
                           value="@FormatDate(entry.EndDate)"
                           disabled="@entry.IsCurrent"
                           @onchange="e => entry.EndDate = ParseNullableDate(e.Value?.ToString())" />
                </div>
                <div class="col-md-4 mb-3 d-flex align-items-end">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="@($"current_{i}")"
                               checked="@entry.IsCurrent"
                               @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                        <label class="form-check-label" for="@($"current_{i}")">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3"
                          @oninput="e => entry.Description = e.Value?.ToString() ?? """>@entry.Description</textarea>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public Dictionary<string, string> Errors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => WorkEntries.Add(new());
    private void RemoveEntry(int index) => WorkEntries.RemoveAt(index);

    private string ErrorClass(string key) => Errors.ContainsKey(key) ? "is-invalid" : "";

    private static string FormatDate(DateTime date) =>
        date == default ? "" : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? "";

    private static DateTime ParseDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : default;

    private static DateTime? ParseNullableDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : null;
}

@namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Components.Pages.Apply
@using static Apply

<h3>References</h3>

@for (int idx = 0; idx < References.Count; idx++)
{
    var i = idx;
    var r = References[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
