namespace sv_fe5c3bf64a7543eabcf20521d982e0df.Models;

/// <summary>
/// Default stub implementation of IApplicationService.
/// Replace with a real implementation that persists data.
/// </summary>
public class DefaultApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public Task<int> SubmitApplicationAsync(JobApplication application)
    {
        var id = Interlocked.Increment(ref _nextId);
        return Task.FromResult(id);
    }

    public Task<bool> ValidateEmailAsync(string email)
    {
        var isValid = !string.IsNullOrWhiteSpace(email)
                      && email.Contains('@')
                      && email.Contains('.');
        return Task.FromResult(isValid);
    }
}

